.app {
  width: 100%;
  box-sizing: border-box;
  font-family: system-ui;
  background: #fff;
  border-radius: var(--appsmith-theme-borderRadius);
  padding: 20px 24px;
  border: 1px solid #e2e8f0;
}

.header-row {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 16px;
  flex-wrap: wrap;
}

.identity {
  display: flex;
  align-items: flex-start;
  gap: 14px;
}

.icon-box {
  width: 44px;
  height: 44px;
  border-radius: 8px;
  background: #f1f5f9;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  font-size: 22px;
}

.label-sm {
  font-size: 13px;
  color: #64748b;
  margin: 0 0 2px;
}

.title-md {
  font-size: 17px;
  font-weight: 600;
  margin: 0;
  color: #0f172a;
}

.title-lg {
  font-size: 22px;
  font-weight: 600;
  margin: 0;
  color: #0f172a;
}

.serial-sm {
  font-size: 13px;
  color: #94a3b8;
  margin: 4px 0 0;
}

.text-right {
  text-align: right;
}

.value-md {
  font-size: 14px;
  font-weight: 600;
  margin: 0;
  color: #0f172a;
}

.dial-row {
  margin-top: 12px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.dial-label {
  font-size: 12px;
  color: #94a3b8;
}

.dial-value {
  font-size: 13px;
  color: #64748b;
}

.divider {
  border-top: 1px solid #e2e8f0;
  margin: 16px 0;
}

.tile-grid {
  display: grid;
  grid-template-columns: 1fr 1fr 1.3fr;
  gap: 12px;
}

.tile-grid-4 {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 12px;
}

.status-badge {
  display: inline-block;
  font-size: 14px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 6px;
}

.status-select-inline {
  font-size: 13px;
  font-weight: 500;
  color: #0f172a;
  padding: 6px 10px;
  border-radius: 8px;
  border: 1px solid #cbd5e1;
  background: #ffffff;
}

.tile {
  border-radius: 8px;
  padding: 12px 14px;
}

.tile-label {
  font-size: 12px;
  margin: 0 0 6px;
  font-weight: 600;
}

.tile-value-lg {
  font-size: 18px;
  font-weight: 600;
}

.tile-value-md {
  font-size: 14px;
  font-weight: 600;
  color: #0f172a;
}

.tile-sub {
  font-size: 11px;
  color: #94a3b8;
  margin: 6px 0 0;
}

.grade-tile {
  background: #eef2ff;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.grade-circle {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background: #ffffff;
  border: 3px solid #4338ca;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.grade-text {
  font-size: 22px;
  font-weight: 600;
  color: #4338ca;
  line-height: 1;
}

.grade-label {
  font-size: 12px;
  color: #4338ca;
  margin: 0 0 6px;
  font-weight: 600;
}

.grade-sub {
  font-size: 11px;
  color: #4338ca;
  margin: 0;
  opacity: 0.85;
}

.status-row {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
  align-items: center;
}

.status-label {
  font-size: 12px;
  color: #64748b;
  margin-right: 4px;
}

.status-tag {
  font-size: 12px;
  padding: 4px 10px;
  border-radius: 8px;
  font-weight: 600;
}

.spacer {
  flex: 1;
}

.btn {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 14px;
  border-radius: 8px;
  border: 1px solid #cbd5e1;
  background: #ffffff;
  color: #0f172a;
  cursor: pointer;
  font-size: 13px;
  font-weight: 500;
}

.btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

