        </>
      )}

      {/* Installed parts tally */}
      {installedParts.length > 0 && (
        <div style={{
          marginTop: '14px',
          background: '#f0fdf4',
          border: '1px solid #bbf7d0',
          borderRadius: '10px',
          padding: '12px 16px'
        }}>
          <div style={{ fontSize: '12px', fontWeight: 700, color: '#15803d', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '8px' }}>
            🔧 Parts Added to This Asset
          </div>
          {installedParts.map((p, i) => (
            <div key={i} style={{
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              padding: '5px 0',
              borderBottom: i < installedParts.length - 1 ? '1px solid #dcfce7' : 'none'
            }}>
              <div>
                <span style={{ fontSize: '13px', color: '#166534', fontWeight: 500 }}>{p.part_type || '—'}</span>
                {p.serial_number && (
                  <span style={{ fontSize: '11px', color: '#4ade80', marginLeft: '8px' }}>S/N: {p.serial_number}</span>
                )}
              </div>
              <span style={{ fontSize: '13px', color: '#15803d', fontWeight: 600 }}>
                {p.part_cost ? '£' + parseFloat(p.part_cost).toFixed(2) : '—'}
              </span>
            </div>
          ))}
          <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            marginTop: '8px',
            paddingTop: '8px',
            borderTop: '2px solid #86efac'
          }}>
            <span style={{ fontSize: '13px', fontWeight: 700, color: '#14532d' }}>Total Parts Cost</span>
            <span style={{ fontSize: '14px', fontWeight: 800, color: '#14532d' }}>£{totalCost.toFixed(2)}</span>
          </div>
        </div>
      )}
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
